    ]
  });

  blocks.push({ type: 'divider' });

  blocks.push({
    type: 'context',
    elements: [{ type: 'mrkdwn', text: 'You can also manage settings by typing commands in a DM  •  e.g. _rename Luna_, _persona witty and casual_, _scope team_deals_' }]
  });
