// Extract context from button value and build agent prompt
// Two-layer pattern: Query API context (in button payload) + MCP enrichment
const payload = $('Parse Interactive Payload').first().json;
let context = {};
try {
  context = JSON.parse(payload.actionValue || '{}');
} catch(e) {
  context = {};
}

const accountName = (context.accountName || context.account_name) || 'the account';
const meetingSubject = (context.meetingSubject || context.meeting_subject) || '';
const participants = (context.participants || context.participant_names) || '';
const repName = (context.repName || context.rep_name) || 'there';
const assistantName = (context.assistantName || context.assistant_name) || 'Aria';
const assistantEmoji = (context.assistantEmoji || context.assistant_emoji) || ':robot_face:';

const meetingSubjectNote = meetingSubject
  ? ` (${meetingSubject})`
  : '';

const todayStr = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

let systemPrompt = `You are ${assistantName}, a personal sales assistant for ${repName}.

You have access to People.ai MCP tools for CRM data, account activity, meeting details, and engagement data.

**FOLLOW-UP EMAIL DRAFT MODE**

TODAY IS ${todayStr}. Remember this date — it is critical for determining meeting recency.

## KNOWN MEETING CONTEXT (from People.ai Query API — confirmed data):
- **Account:** ${accountName}
- **Meeting Subject:** ${meetingSubject || '[not available]'}
- **Participants:** ${participants || '[not available]'}

This meeting data comes from the People.ai Query API and is CONFIRMED — the meeting definitely happened. Use this as your primary anchor.

## MEETING RECAP CONTEXT (from AI-generated recap):
\${context.recapContext ? context.recapContext : '[No recap context available — research from scratch]'}

Use this recap context to anchor your follow-up email. The recap was generated from transcript data and is more reliable than generic account context.

## CRITICAL: DATA LATENCY PROTOCOL
People.ai transcript data takes 3-4 HOURS to appear after a meeting ends.
The meeting above may not have full transcript/notes available via MCP yet.

**YOU MUST FOLLOW THIS PROTOCOL:**
1. Use People.ai MCP tools to search for this meeting and try to get detailed notes, topics, and action items
2. **IF MCP has rich data** (transcript, topics, action items) → Great, use it all to draft a detailed email
3. **IF MCP has limited/no data for this meeting** → This is normal for recent meetings. You still KNOW the meeting happened because of the Query API data above. Draft a meaningful email using:
   - The meeting subject as the anchor topic
   - The account context and relationship history from MCP
   - The participant list for To/CC fields
   - A professional, forward-looking tone referencing "our conversation"
   - Add a note: "_Details from this meeting are still syncing. Reply with key discussion points and I\\'ll make this draft more specific._"
4. **NEVER say you cannot find the meeting** — you have confirmed data above that it happened
5. **NEVER draft based on an older meeting** — the user clicked the button for THIS specific meeting

## DRAFTING INSTRUCTIONS
Use People.ai MCP tools to:
1. Find the specific meeting with ${accountName} — look for notes, topics, action items
2. Extract what was actually discussed (not general deal context)
3. Look up participant emails to personalize the To/CC fields

**CRITICAL:** Anchor the email on THIS specific meeting${meetingSubjectNote}.
- Lead with topics, decisions, and action items from the meeting
- Do NOT pad with generic deal/pipeline context unless it was discussed
- If meeting notes are thin, use the meeting subject and account context to draft a relevant follow-up

**DATE AWARENESS — adjust your follow-up language based on when the meeting was:**
- Same day: "Thanks for the conversation today"
- Yesterday: "Thanks for the conversation yesterday"
- 2-3 days ago: "I wanted to follow up on our conversation from {day}"
- 4-7 days ago: "Circling back on our discussion last {day}"

**FORMAT** (Slack mrkdwn):

:email: *Follow-up Draft — ${accountName}*

*To:* primary recipient ({email@company.com}) — ALWAYS include email address. Use People.ai MCP to look up emails.
*CC:* other meeting participants with emails — internal team and external contacts
*Subject:* concise subject line

---
email body — 150-250 words, professional, references meeting topics, includes clear next step
---

_Reply in this thread to adjust the tone, add details, or ask me to revise._

**RULES:**
- Keep the email 150-250 words
- Reference specific discussion topics from THIS meeting — do NOT fabricate topics
- If MCP data is limited, draft based on the meeting subject and note that details are still syncing
- Include a clear call to action / next step
- Use contact names, not generic "team"
- Tone: professional but warm
- ALWAYS sign the email as ${repName}. Do NOT sign as the account owner or AE — the person requesting the draft is ${repName}.
- Do NOT use ### headers
- Keep under 3000 characters`;

const agentPrompt = `Draft a follow-up email for my meeting with ${accountName}` +
  (meetingSubject ? `. The meeting was about: ${meetingSubject}` : '') +
  (participants ? `. Participants included: ${participants}` : '') +
  `. Today is ${todayStr}.` +
  `\n\nIMPORTANT: Even if MCP tools don't return detailed transcript data for this meeting, you KNOW it happened. Draft based on the meeting subject and account context.`;

return [{
  json: {
    ...payload,
    ...context,
    systemPrompt,
    agentPrompt,
    assistantName,
    assistantEmoji,
    accountName,
  }
}];

// Parse overflow menu selection and build mute payload + updated message
const payload = $('Parse Interactive Payload').first().json;
const routeData = $('Route Silence Action').first().json;
const selectedValue = routeData.selectedOptionValue || '';
const messageBlocks = routeData.messageBlocks || [];

// Parse compact "action|accountName" format (e.g. "s7|Elastic", "ml|Cyberhaven")
const pipeIdx = selectedValue.indexOf('|');
if (pipeIdx === -1) {
  return [{ json: { error: 'Invalid selection value', selectedValue } }];
}

const actionCode = selectedValue.substring(0, pipeIdx);
const accountName = selectedValue.substring(pipeIdx + 1);

// Get userId and organizationId from Lookup User (Action) — already fetched by the handler
const userRecord = $('Lookup User (Action)').first().json;
const userId = userRecord.id || '';
const organizationId = userRecord.organization_id || '';

// Determine mute parameters
let muteReason, mutedUntil, confirmText;
const now = new Date();

if (actionCode === 's7') {
  muteReason = 'snoozed';
  const until = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
  mutedUntil = until.toISOString();
  confirmText = `:white_check_mark: *${accountName}* snoozed for 7 days.`;
} else if (actionCode === 's30') {
  muteReason = 'snoozed';
  const until = new Date(now.getTime() + 30 * 24 * 60 * 60 * 1000);
  mutedUntil = until.toISOString();
  confirmText = `:white_check_mark: *${accountName}* snoozed for 30 days.`;
} else if (actionCode === 'ml') {
  muteReason = 'marked_lost';
  mutedUntil = null;
  confirmText = `:white_check_mark: *${accountName}* muted — consider closing the open opps in Salesforce.`;
} else {
  return [{ json: { error: 'Unknown action: ' + actionCode } }];
}

// Build mute row for upsert
const mutePayload = {
  user_id: userId,
  organization_id: organizationId,
  alert_type_id: 'silence_contract',
  entity_name: accountName,
  mute_reason: muteReason,
  muted_at: now.toISOString(),
  muted_until: mutedUntil,
  unmuted_at: null
};

// Rebuild message blocks — replace the actioned account's section with confirmation
const updatedBlocks = [];
for (const block of messageBlocks) {
  if (block.type === 'section' && block.text && block.text.text &&
      block.text.text.includes('*' + accountName + '*') && block.accessory) {
    // Replace this section with confirmation (no accessory)
    updatedBlocks.push({
      type: 'section',
      text: { type: 'mrkdwn', text: confirmText }
    });
  } else {
    updatedBlocks.push(block);
  }
}

return [{ json: {
  mutePayload,
  updatedBlocks: JSON.stringify(updatedBlocks),
  channelId: payload.channelId,
  messageTs: payload.messageTs,
  accountName,
  confirmText
} }];

const payload = $('Parse Interactive Payload').first().json;
const selectedValue = payload.selectedOptionValue || payload.actionValue || '';

const pipeIdx = selectedValue.indexOf('|');
if (pipeIdx === -1) {
  return [{ json: { error: 'Invalid selection value', selectedValue } }];
}

const actionCode = selectedValue.substring(0, pipeIdx);
const accountName = selectedValue.substring(pipeIdx + 1);

const userRecord = $('Lookup User (Action)').first().json;

return [{
  json: {
    actionCode,
    accountName,
    channelId: payload.channelId,
    messageTs: payload.messageTs,
    assistantName: userRecord.assistant_name || userRecord.org_default_assistant_name || 'Aria',
    assistantEmoji: userRecord.assistant_emoji || userRecord.org_default_assistant_emoji || ':sparkles:',
    repName: userRecord.full_name || 'there',
    userId: userRecord.id || '',
    organizationId: userRecord.organization_id || '',
    isDraftFollowup: actionCode === 'fd',
    selectedOptionValue: selectedValue,
    // Pass through for mute path
    messageBlocks: payload.messageBlocks || [],
  }
}];

// Parse To, Subject, Body from agent draft and build mailto link
const agentOutput = $('Followup Draft Agent').first().json.output || '';
const context = $('Build Followup Context').first().json;

// Parse fields from Slack mrkdwn format
const toMatch = agentOutput.match(/\*To:\*\s*(.+)/i);
const ccMatch = agentOutput.match(/\*CC:\*\s*(.+)/i);
const subjectMatch = agentOutput.match(/\*Subject:\*\s*(.+)/i);

// Extract email address from "Name (Title) <email>" or plain email
function extractEmail(line) {
  const angleMatch = line.match(/<([^>]+@[^>]+)>/);
  if (angleMatch) return angleMatch[1].trim();
  const parenMatch = line.match(/\(([^)]+@[^)]+)\)/);
  if (parenMatch) return parenMatch[1].trim();
  const plainMatch = line.match(/[\w.+-]+@[\w.-]+\.\w+/);
  if (plainMatch) return plainMatch[0].trim();
  return line.trim();
}

const toRaw = toMatch ? toMatch[1].trim() : '';
const ccRaw = ccMatch ? ccMatch[1].trim() : '';
const toEmail = toRaw ? extractEmail(toRaw) : '';
// Extract all emails from a line (for CC with multiple recipients)
function extractAllEmails(line) {
  const emails = [];
  const regex = /[\w.+-]+@[\w.-]+\.\w+/g;
  let m;
  while ((m = regex.exec(line)) !== null) {
    emails.push(m[0].trim());
  }
  return emails.join(',');
}
const ccEmail = ccRaw ? extractAllEmails(ccRaw) : '';
const subject = subjectMatch ? subjectMatch[1].trim() : '';

// Extract email body: between Subject line and "Next Steps" / "_Reply in this thread"
// Extract email body between the --- dividers (after Subject, before trailing ---)
let body = '';
if (subjectMatch) {
  const startIdx = agentOutput.indexOf(subjectMatch[0]) + subjectMatch[0].length;
  let afterSubject = agentOutput.substring(startIdx);

  // The email body is typically wrapped in --- dividers
  const openDivider = afterSubject.indexOf('---');
  if (openDivider > -1) {
    const bodyStart = openDivider + 3;
    const closeDivider = afterSubject.indexOf('\n---', bodyStart);
    if (closeDivider > -1) {
      body = afterSubject.substring(bodyStart, closeDivider).trim();
    } else {
      body = afterSubject.substring(bodyStart).trim();
    }
  } else {
    body = afterSubject.trim();
  }

  // Trim at any Slack UI chrome that leaked through
  const uiMarkers = [
    '\n_Reply in this thread',
    '\n_Reply to adjust',
    '\n:warning:',
    '\n\u26a0',
    '\n*Next Steps',
  ];
  for (const marker of uiMarkers) {
    const idx = body.indexOf(marker);
    if (idx > -1) body = body.substring(0, idx).trim();
  }

  body = body.replace(/^---\s*/, '').replace(/\s*---$/, '').trim();
}

// Strip Slack mrkdwn for plain-text email
const plainBody = body
  .replace(/\*\*([^*]+)\*\*/g, '$1')  // **double bold** (Markdown)
  .replace(/\*([^*]+)\*/g, '$1')       // *single bold* (Slack mrkdwn)
  .replace(/_([^_]+)_/g, '$1')          // _italic_
  .replace(/~([^~]+)~/g, '$1')          // ~strikethrough~
  .replace(/:[a-z0-9_+-]+:/g, '')       // :emoji: codes
  .replace(/•/g, '-')                    // bullet chars
  .replace(/- \*\*/g, '- ')             // leftover bold after bullets
  .replace(/\*\*$/gm, '')               // trailing bold markers
  .replace(/\n{3,}/g, '\n\n')           // excess newlines
  .trim();

// Build Gmail compose deep link
let composeUrl = '';
if (toEmail || subject) {
  const params = ['view=cm', 'fs=1'];
  if (toEmail) params.push('to=' + encodeURIComponent(toEmail));
  if (ccEmail) params.push('cc=' + encodeURIComponent(ccEmail));
  if (subject) params.push('su=' + encodeURIComponent(subject));
  if (plainBody) params.push('body=' + encodeURIComponent(plainBody));
  composeUrl = 'https://mail.google.com/mail/?' + params.join('&');
}

// Truncate if too long
const MAX_URL = 7500;
if (composeUrl.length > MAX_URL) {
  const truncBody = plainBody.substring(0, 2000) + '\n\n[... see full draft in Slack thread]';
  const params2 = ['view=cm', 'fs=1'];
  if (toEmail) params2.push('to=' + encodeURIComponent(toEmail));
  if (ccEmail) params2.push('cc=' + encodeURIComponent(ccEmail));
  if (subject) params2.push('su=' + encodeURIComponent(subject));
  params2.push('body=' + encodeURIComponent(truncBody));
  composeUrl = 'https://mail.google.com/mail/?' + params2.join('&');
}

// Build Block Kit: draft text + mailto button
const blocks = [
  {
    type: "section",
    text: { type: "mrkdwn", text: agentOutput.substring(0, 2999) }
  }
];

if (composeUrl) {
  blocks.push({
    type: "actions",
    elements: [{
      type: "button",
      text: { type: "plain_text", text: ":email: Open in Gmail", emoji: true },
      url: composeUrl,
      style: "primary"
    }]
  });
}

return [{
  json: {
    blocks: JSON.stringify(blocks),
    fallbackText: agentOutput,
    composeUrl,
    toEmail,
    subject,
  }
}];

