// Bridge recap draft request to existing followup flow
// Enriches the existing flow with recap context
const payload = $('Parse Interactive Payload').first().json;
let context = {};
try { context = JSON.parse(payload.actionValue || '{}'); } catch(e) {}

// Reformat to match what Build Followup Context expects in actionValue
const enrichedValue = JSON.stringify({
  accountName: context.account_name || '',
  accountId: context.account_id || '',
  activityUid: context.activity_uid || '',
  meetingSubject: context.meeting_subject || '',
  participants: context.participants || '',
  userId: context.user_id || '',
  dbUserId: context.db_user_id || context.user_id || '',
  slackUserId: context.slack_user_id || '',
  organizationId: context.organization_id || '',
  assistantName: context.assistant_name || 'Aria',
  assistantEmoji: context.assistant_emoji || ':robot_face:',
  repName: context.rep_name || '',
  recapContext: context.follow_up_context || '',
});

return [{ json: {
  ...payload,
  actionValue: enrichedValue,
  actionId: 'followup_draft',
}}];

const payload = $('Parse Interactive Payload').first().json;
let context = {};
try { context = JSON.parse(payload.actionValue || '{}'); } catch(e) {}

const summary = context.summary || '';
const decisions = (context.key_decisions || []).map(d => '\u2022 ' + d).join('\n');
const tasks = (context.tasks || []).map(t => {
  let line = '\u2022 ' + t.description;
  if (t.owner) line += ' \u2014 ' + t.owner;
  if (t.due_hint) line += ' (' + t.due_hint + ')';
  return line;
}).join('\n');

// Store context in private_metadata for the submission handler
const privateMetadata = JSON.stringify({
  account_name: context.account_name || '',
  account_id: context.account_id || '',
  activity_uid: context.activity_uid || '',
  meeting_subject: context.meeting_subject || '',
  meeting_date: context.meeting_date || '',
  meeting_time: context.meeting_time || '',
  user_id: context.user_id || '',
  slack_user_id: context.slack_user_id || '',
  rep_name: context.rep_name || '',
  rep_email: context.rep_email || '',
  channel_id: payload.channelId || '',
  message_ts: payload.messageTs || '',
  assistant_name: context.assistant_name || 'Aria',
  assistant_emoji: context.assistant_emoji || ':robot_face:',
  meeting_category: context.meeting_category || '',
});

const modal = {
  trigger_id: payload.triggerId,
  view: {
    type: "modal",
    callback_id: "save_recap_to_sf",
    title: { type: "plain_text", text: "Save Recap to Salesforce" },
    submit: { type: "plain_text", text: "Save to Salesforce" },
    close: { type: "plain_text", text: "Cancel" },
    private_metadata: privateMetadata,
    blocks: [
      {
        type: "header",
        text: { type: "plain_text", text: "Personal Assistant Suggestions" }
      },
      {
        type: "input",
        block_id: "summary_block",
        label: { type: "plain_text", text: "Summary" },
        element: {
          type: "plain_text_input",
          action_id: "summary_value",
          multiline: true,
          initial_value: summary
        }
      },
      {
        type: "input",
        block_id: "decisions_block",
        label: { type: "plain_text", text: "Key Decisions" },
        element: {
          type: "plain_text_input",
          action_id: "decisions_value",
          multiline: true,
          initial_value: decisions
        },
        optional: true
      },
      {
        type: "input",
        block_id: "tasks_block",
        label: { type: "plain_text", text: "Action Items" },
        element: {
          type: "plain_text_input",
          action_id: "tasks_value",
          multiline: true,
          initial_value: tasks
        },
        optional: true
      },
      ...(function() {
        const meetOpts = [
          "Discovery Meeting",
          "Demo Meeting",
          "Proposal Meeting",
          "Security Meeting",
          "Procurement Meeting",
          "Legal Meeting"
        ].map(v => ({ text: { type: "plain_text", text: v }, value: v }));

        const meetBlock = {
          type: "input",
          block_id: "meeting_category_block",
          label: { type: "plain_text", text: "AI Suggested Category" },
          element: {
            type: "static_select",
            action_id: "meeting_category_value",
            placeholder: { type: "plain_text", text: "Select Meeting Type" },
            options: meetOpts,
          },
          optional: true
        };
        if (context.meeting_category && meetOpts.some(o => o.value === context.meeting_category)) {
          meetBlock.element.initial_option = { text: { type: "plain_text", text: context.meeting_category }, value: context.meeting_category };
        }
        return [meetBlock];
      })(),
    ]
  }
};

return [{ json: modal }];

const p = $('Parse Interactive Payload').first().json;
const vals = p.submittedValues || {};
let meta = {};
try { meta = JSON.parse(p.view_private_metadata || '{}'); } catch(e) {}

const summary = vals.summary_value || '';
const decisions = vals.decisions_value || '';
const tasks = vals.tasks_value || '';
const meetingCategory = vals.meeting_category_value || meta.meeting_category || '';

const description = [
  'Summary:',
  summary,
  '',
  decisions ? 'Key Decisions:\n' + decisions : '',
  '',
  tasks ? 'Action Items:\n' + tasks : '',
].filter(Boolean).join('\n');

return [{ json: {
  webhook_payload: {
    action: 'log_activity',
    salesforce_object: 'Event',
    fields: {
      Subject: meta.meeting_subject || 'Customer Meeting',
      Description: description,
      ActivityDate: new Date().toLocaleDateString('en-CA', { timeZone: 'America/Los_Angeles' }),
      meeting_category: meetingCategory,
    },
    context: {
      user_email: meta.rep_email || '',
      account_name: meta.account_name || '',
      activity_uid: meta.activity_uid || '',
    }
  },
  channelId: meta.channel_id || '',
