parameters.jsCode:
// Open a modal for creating a task in Salesforce
const payload = $('Parse Interactive Payload').first().json;
let context = {};
try { context = JSON.parse(payload.actionValue || '{}'); } catch(e) {}

// Store context in private_metadata for the submission handler
const privateMetadata = JSON.stringify({
  account_name: context.account_name || '',
  account_id: context.account_id || '',
  activity_uid: context.activity_uid || '',
  meeting_subject: context.meeting_subject || '',
  user_id: context.user_id || '',
  slack_user_id: context.slack_user_id || '',
  rep_name: context.rep_name || '',
  rep_email: context.rep_email || '',
  channel_id: payload.channelId || '',
  message_ts: payload.messageTs || '',
  assistant_name: context.assistant_name || 'Aria',
  assistant_emoji: context.assistant_emoji || ':robot_face:',
  task_category: context.task_category || '',
  task_owner_email: context.task_owner_email || '',
});

const roleOpts = [
  { text: { type: "plain_text", text: "CSM" }, value: "CSM" },
  { text: { type: "plain_text", text: "AE" }, value: "AE" },
  { text: { type: "plain_text", text: "SE" }, value: "SE" },
  { text: { type: "plain_text", text: "AI" }, value: "AI" }
];

const roleElement = {
  type: "static_select",
  action_id: "task_role_value",
  placeholder: { type: "plain_text", text: "Select role" },
  options: roleOpts,
};
if (['CSM', 'AE', 'SE', 'AI'].includes(context.assignee_role)) {
  roleElement.initial_option = { text: { type: "plain_text", text: context.assignee_role }, value: context.assignee_role };
}

const modal = {
  trigger_id: payload.triggerId,
  view: {
    type: "modal",
    callback_id: "save_task_to_sf",
    title: { type: "plain_text", text: "Create Salesforce Task" },
    submit: { type: "plain_text", text: "Create Task" },
    close: { type: "plain_text", text: "Cancel" },
    private_metadata: privateMetadata,
    blocks: [
      {
        type: "input",
        block_id: "task_desc_block",
        label: { type: "plain_text", text: "Task Description" },
        element: {
          type: "plain_text_input",
          action_id: "task_desc_value",
          multiline: true,
          initial_value: context.task_description || ''
        }
      },
      {
        type: "input",
        block_id: "task_owner_block",
        label: { type: "plain_text", text: "Assigned To (email)" },
        element: {
          type: "plain_text_input",
          action_id: "task_owner_value",
          initial_value: context.task_owner_email || context.task_owner || ($('Lookup User (Action)').first().json.email || '')
        }
      },
      {
        type: "input",
        block_id: "task_role_block",
        label: { type: "plain_text", text: "AI Suggested Role" },
        element: roleElement,
        optional: true
      },
      {
        type: "input",
        block_id: "task_duration_block",
        label: { type: "plain_text", text: "Estimated Duration (minutes)" },
        element: {
          type: "plain_text_input",
          action_id: "task_duration_value",
          initial_value: String(parseInt(context.duration_minutes) || 30)
        },
        optional: true
      },
      ...(function() {
        // Convert due_hint to an actual date for the datepicker
        const now = new Date();
        const ptNow = new Date(now.toLocaleString('en-US', { timeZone: 'America/Los_Angeles' }));
        let dueDate = '';
        const hint = (context.task_due_hint || '').toLowerCase();
        if (hint.includes('asap') || hint.includes('today') || hint.includes('immediate')) {
          dueDate = ptNow.toISOString().split('T')[0];
        } else if (hint.includes('tomorrow')) {
          const d = new Date(ptNow.getTime() + 86400000);
          dueDate = d.toISOString().split('T')[0];
        } else if (hint.includes('friday') || hint.includes('end of week') || hint.includes('this week')) {
          const d = new Date(ptNow);
          d.setDate(d.getDate() + ((5 - d.getDay() + 7) % 7 || 7));
          dueDate = d.toISOString().split('T')[0];
        } else if (hint.includes('next week')) {
          const d = new Date(ptNow.getTime() + 7 * 86400000);
          dueDate = d.toISOString().split('T')[0];
        } else {
          const d = new Date(ptNow.getTime() + 7 * 86400000);
          dueDate = d.toISOString().split('T')[0];
        }
        const block = {
          type: "input",
          block_id: "task_due_block",
          label: { type: "plain_text", text: "Due Date" },
          element: {
            type: "datepicker",
            action_id: "task_due_value",
          },
          optional: true
        };
        if (dueDate) {
          block.element.initial_date = dueDate;
        }
        return [block];
      })(),
      ...(function() {
        const catOpts = [
          "Discovery Meeting",
          "Demo Meeting",
          "Prospecting & Qualification",
          "Solution Presentation & Demo",
          "Commercials & Negotiation",
          "Technical Scoping & Solutioning",
          "Onboarding & Implementation",
          "Account & Renewal Management",
          "Expansion & Upsell",
          "Customer Training",
          "Internal Deal Support (Legal/Fin/Sec)",
          "Product & Engineering Inquiry",
          "Strategic Account & Territory Planning",
          "Sales Operations & Coaching"
        ].map(v => ({ text: { type: "plain_text", text: v }, value: v }));
        const block = {
          type: "input",
          block_id: "task_category_block",
          label: { type: "plain_text", text: "AI Suggested Category" },
          element: {
            type: "static_select",
            action_id: "task_category_value",
            placeholder: { type: "plain_text", text: "Select category" },
            options: catOpts,
          },
          optional: true
        };
        if (context.task_category && catOpts.some(o => o.value === context.task_category)) {
          block.element.initial_option = { text: { type: "plain_text", text: context.task_category }, value: context.task_category };
        }
        return [block];
      })(),
      {
        type: "context",
        elements: [{ type: "mrkdwn", text: '<https://glass.people.ai/sheet/514ff6d1-7e51-4bab-872e-b1f35ce13f5b|My Open Tasks>  \u00b7  <https://glass.people.ai/sheet/3be9132b-cf08-4f94-9164-651bb5804e51|My Completed Tasks>  \u00b7  <https://glass.people.ai/sheet/40ce97c4-0237-4afb-8d47-b10cf4792253|Last 30 Days>' }]
      }
    ]
  }
};

return [{ json: modal }];

// Build Workato webhook payload from task modal submission
const p = $('Parse Interactive Payload').first().json;
const vals = p.submittedValues || {};
let meta = {};
try { meta = JSON.parse(p.view_private_metadata || '{}'); } catch(e) {}

const description = vals.task_desc_value || '';
const owner = vals.task_owner_value || '';
const role = vals.task_role_value || '';
const duration = vals.task_duration_value || '30';
const dueDate = vals.task_due_value || '';
const category = vals.task_category_value || '';

return [{ json: {
  webhook_payload: {
    action: 'create_task',
    salesforce_object: 'Task',
    fields: {
      Subject: description.substring(0, 255),
      Description: 'From meeting: ' + (meta.meeting_subject || '') + ' with ' + (meta.account_name || '') +
        '\nAssigned to: ' + owner + ' (' + role + ')' +
        '\nEstimated duration: ' + (parseInt(String(duration).replace(/[^0-9]/g, '')) || 30) + ' minutes',
      ActivityDate: dueDate,
      Status: 'Not Started',
      Priority: 'Normal',
      TaskDuration: parseInt(String(duration).replace(/[^0-9]/g, '')) || 30,
      Category: category,
    },
    context: {
      user_email: meta.rep_email || '',
      account_name: meta.account_name || '',
      meeting_subject: meta.meeting_subject || '',
      activity_uid: meta.activity_uid || '',
      assignee_name: meta.rep_name || '',
      assignee_email: owner,
      assignee_role: role,
    }
  },
  channelId: meta.channel_id || '',
  messageTs: meta.message_ts || '',
  slackUserId: meta.slack_user_id || '',
  task_description: description,
  assistantName: meta.assistant_name || 'Aria',
  assistantEmoji: meta.assistant_emoji || ':robot_face:',
}}];

// Build a modal showing all tasks with checkboxes
const payload = $('Parse Interactive Payload').first().json;
let context = {};
try { context = JSON.parse(payload.actionValue || '{}'); } catch(e) {}

const tasks = context.tasks || [];
const accountName = context.account_name || 'Meeting';
const meetingSubject = context.meeting_subject || '';

const options = tasks.map((t, i) => ({
  text: { type: "mrkdwn", text: '*' + t.d + '*\n' + t.o + ' (' + t.r + ') \u00b7 ' + t.m + ' min' },
  value: String(i)
}));

const initialOptions = [...options];

const privateMetadata = JSON.stringify({
  account_name: accountName,
  meeting_subject: meetingSubject,
  tasks: tasks,
  channel_id: payload.channelId || '',
  message_ts: payload.messageTs || '',
  assistant_name: context.assistant_name || 'Aria',
  assistant_emoji: context.assistant_emoji || ':robot_face:',
});

const blocks = [
  {
    type: "header",
    text: { type: "plain_text", text: accountName + " \u2014 Tasks" }
  },
  {
    type: "section",
    text: { type: "mrkdwn", text: "_Select tasks to create in Salesforce with AI-suggested details. To edit a task before creating, close this modal and use the individual task buttons in the thread._" }
  },
  {
    type: "context",
    elements: [{ type: "mrkdwn", text: "<https://glass.people.ai/sheet/514ff6d1-7e51-4bab-872e-b1f35ce13f5b|My Open Tasks>  \u00b7  <https://glass.people.ai/sheet/3be9132b-cf08-4f94-9164-651bb5804e51|My Completed Tasks>  \u00b7  <https://glass.people.ai/sheet/40ce97c4-0237-4afb-8d47-b10cf4792253|Last 30 Days>" }]
  }
];

if (options.length > 0) {
  blocks.push({
    type: "input",
    block_id: "tasks_checklist",
    label: { type: "plain_text", text: "Tasks to create" },
    element: {
      type: "checkboxes",
      action_id: "selected_tasks",
      options: options,
      initial_options: initialOptions
    }
  });
} else {
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: "_No tasks found._" }
  });
}

const modal = {
  trigger_id: payload.triggerId,
  view: {
    type: "modal",
    callback_id: "batch_create_tasks",
    title: { type: "plain_text", text: "Create Tasks" },
    submit: { type: "plain_text", text: "Create Selected" },
    close: { type: "plain_text", text: "Cancel" },
    private_metadata: privateMetadata,
    blocks: blocks
  }
};

return [{ json: modal }];

// Build individual Workato payloads for each selected task
const p = $('Parse Interactive Payload').first().json;
const vals = p.submittedValues || {};
let meta = {};
try { meta = JSON.parse(p.view_private_metadata || '{}'); } catch(e) {}

const selectedIndices = (vals.selected_tasks || []).map(opt => parseInt(opt));
const tasks = meta.tasks || [];

const now = new Date();
const ptNow = new Date(now.toLocaleString('en-US', { timeZone: 'America/Los_Angeles' }));

function parseDueDate(hint) {
  const h = (hint || '').toLowerCase();
  if (h.includes('today') || h.includes('asap') || h.includes('immediate')) return ptNow.toISOString().split('T')[0];
  if (h.includes('tomorrow')) { const d = new Date(ptNow.getTime() + 86400000); return d.toISOString().split('T')[0]; }
  if (h.includes('friday') || h.includes('this week') || h.includes('end of week')) {
    const d = new Date(ptNow); d.setDate(d.getDate() + ((5 - d.getDay() + 7) % 7 || 7)); return d.toISOString().split('T')[0];
  }
  if (h.includes('next week')) { const d = new Date(ptNow.getTime() + 7 * 86400000); return d.toISOString().split('T')[0]; }
  const d = new Date(ptNow.getTime() + 7 * 86400000); return d.toISOString().split('T')[0];
}

const results = [];
for (const idx of selectedIndices) {
  const t = tasks[idx];
  if (!t) continue;
  results.push({
    json: {
      webhook_payload: {
        action: 'create_task',
        salesforce_object: 'Task',
        fields: {
          Subject: (t.d || '').substring(0, 255),
          Description: 'From meeting: ' + (meta.meeting_subject || '') + ' with ' + (meta.account_name || '') +
            '\nAssigned to: ' + (t.o || '') + ' (' + (t.r || '') + ')' +
            '\nEstimated duration: ' + (t.m || 30) + ' minutes',
          ActivityDate: parseDueDate(t.h),
          Status: 'Not Started',
          Priority: 'Normal',
          TaskDuration: parseInt(t.m) || 30,
          Category: t.c || '',
        },
        context: {
          user_email: '',
          account_name: meta.account_name || '',
          meeting_subject: meta.meeting_subject || '',
          assignee_name: t.o || '',
          assignee_email: t.e || '',
          assignee_role: t.r || '',
        }
      },
      channelId: meta.channel_id || '',
      messageTs: meta.message_ts || '',
      task_description: t.d || '',
      assistantName: meta.assistant_name || 'Aria',
      assistantEmoji: meta.assistant_emoji || ':robot_face:',
      taskIndex: idx,
      totalSelected: selectedIndices.length,
    }
  });
}

if (results.length === 0) return [{ json: { skip: true } }];
return results;

const payload = $('Parse Interactive Payload').first().json;
let context = {};
try { context = JSON.parse(payload.actionValue || '{}'); } catch(e) {}

return [{ json: {
  webhook_payload: {
    action: 'update_task',
    task_id: context.task_id || '',
    fields: { Status: 'Completed' }
  },
  channelId: payload.channelId || '',
  messageTs: payload.messageTs || '',
  taskSubject: context.task_subject || '',
  accountName: context.account_name || '',
  userId: payload.userId || '',
}}];

const payload = $('Parse Interactive Payload').first().json;
let context = {};
try { context = JSON.parse(payload.actionValue || '{}'); } catch(e) {}

const skill = context.skill || '';
const accountName = context.account_name || '';
const accountId = context.account_id || '';
const taskSubject = context.task_subject || '';

// Reformat to match what Bridge Recap to Draft expects
const enrichedValue = JSON.stringify({
  accountName,
  accountId,
  activityUid: '',
  meetingSubject: '',
  participants: '',
  userId: context.user_id || '',
  dbUserId: context.user_id || '',
  slackUserId: context.slack_user_id || '',
  organizationId: context.organization_id || '',
  assistantName: context.assistant_name || 'Aria',
  assistantEmoji: context.assistant_emoji || ':robot_face:',
  repName: context.rep_name || '',
  recapContext: 'Task: ' + taskSubject,
});

return [{ json: {
  ...payload,
  actionValue: enrichedValue,
  actionId: 'followup_draft',
  routeSkill: skill,
}}];

const body = $('Interactive Webhook').first().json.body;

// Slack sends payload as URL-encoded form: payload=<json string>
// n8n auto-parses URL-encoded bodies, so body.payload is already decoded
let rawPayload = body.payload;
if (typeof rawPayload !== 'string') {
  rawPayload = JSON.stringify(rawPayload);
}

const payload = JSON.parse(rawPayload);

const type = payload.type;
const userId = (payload.user && payload.user.id) ? payload.user.id : null;
const triggerId = payload.trigger_id || null;

// For block_actions
const actions = payload.actions || [];
const actionId = (actions[0] && actions[0].action_id) ? actions[0].action_id : null;

// For view_submission
const callbackId = (payload.view && payload.view.callback_id) ? payload.view.callback_id : null;
const viewStateValues = (payload.view && payload.view.state && payload.view.state.values)
  ? payload.view.state.values : {};

// Flatten state.values: { block_id: { action_id: { type, value } } } → { action_id: value }
const submittedValues = {};
for (const blockId of Object.keys(viewStateValues)) {
  const actions = viewStateValues[blockId];
  for (const aId of Object.keys(actions)) {
    const el = actions[aId];
    if (el.type === 'plain_text_input') {
      submittedValues[aId] = el.value || '';
    } else if (el.type === 'radio_buttons') {
      submittedValues[aId] = el.selected_option ? el.selected_option.value : null;
    } else if (el.type === 'checkboxes') {
      submittedValues[aId] = (el.selected_options || []).map(o => o.value);
    } else if (el.type === 'datepicker') {
      submittedValues[aId] = el.selected_date || '';
    } else if (el.type === 'static_select') {
      submittedValues[aId] = el.selected_option ? el.selected_option.value : null;
    }
  }
}


// Follow-up button context
const actionValue = (payload.actions && payload.actions[0]) ? (payload.actions[0].value || '') : '';
const selectedOptionValue = (payload.actions && payload.actions[0] && payload.actions[0].selected_option) ? payload.actions[0].selected_option.value : '';
const messageTs = (payload.message && payload.message.ts) ? payload.message.ts : '';
const channelId = (payload.channel && payload.channel.id) ? payload.channel.id : '';

const messageBlocks = payload.message ? (payload.message.blocks || []) : [];


// Extract view private_metadata for modal submissions
const view_private_metadata = (payload.view && payload.view.private_metadata) ? payload.view.private_metadata : '';
return [{ json: { type, userId, triggerId, actionId, actionValue, selectedOptionValue, messageTs, channelId, messageBlocks, callbackId, submittedValues, view_private_metadata } }];

const user = $('Lookup User (Action)').first().json;
const currentName = (user && user.assistant_name) ? user.assistant_name : 'Aria';
const triggerId = $('Parse Interactive Payload').first().json.triggerId;

const modal = {
  type: 'modal',
  callback_id: 'save_name',
  title: { type: 'plain_text', text: 'Edit Assistant Name' },
  submit: { type: 'plain_text', text: 'Save' },
  close: { type: 'plain_text', text: 'Cancel' },
  blocks: [
    {
      type: 'input',
      block_id: 'name_block',
      label: { type: 'plain_text', text: 'Assistant Name' },
      element: {
        type: 'plain_text_input',
        action_id: 'name_value',
        initial_value: currentName,
        placeholder: { type: 'plain_text', text: 'e.g. ScottAI, Luna, Aria' },
        max_length: 50
      }
    }
  ]
};

return [{ json: { triggerId, modal: JSON.stringify(modal) } }];

const user = $('Lookup User (Action)').first().json;
const currentEmoji = (user && user.assistant_emoji) ? user.assistant_emoji : ':robot_face:';
const triggerId = $('Parse Interactive Payload').first().json.triggerId;

const modal = {
  type: 'modal',
  callback_id: 'save_emoji',
  title: { type: 'plain_text', text: 'Edit Assistant Emoji' },
  submit: { type: 'plain_text', text: 'Save' },
  close: { type: 'plain_text', text: 'Cancel' },
  blocks: [
    {
      type: 'input',
      block_id: 'emoji_block',
      label: { type: 'plain_text', text: 'Emoji' },
      hint: { type: 'plain_text', text: 'Use :emoji_name: format. Custom workspace emojis work too.' },
      element: {
        type: 'plain_text_input',
        action_id: 'emoji_value',
        initial_value: currentEmoji,
        placeholder: { type: 'plain_text', text: ':rocket: or :crystal_ball:' }
      }
    }
  ]
};

return [{ json: { triggerId, modal: JSON.stringify(modal) } }];

const user = $('Lookup User (Action)').first().json;
const currentPersona = (user && user.assistant_persona) ? user.assistant_persona : 'direct, action-oriented, conversational';
const triggerId = $('Parse Interactive Payload').first().json.triggerId;

const modal = {
  type: 'modal',
  callback_id: 'save_persona',
  title: { type: 'plain_text', text: 'Edit Persona' },
  submit: { type: 'plain_text', text: 'Save' },
  close: { type: 'plain_text', text: 'Cancel' },
  blocks: [
    {
      type: 'section',
      text: { type: 'mrkdwn', text: 'Describe how your assistant should sound. This affects the tone of all briefings and responses.' }
    },
    {
      type: 'input',
      block_id: 'persona_block',
      label: { type: 'plain_text', text: 'Personality' },
      hint: { type: 'plain_text', text: "Examples: 'direct and data-driven', 'witty and casual', 'formal and structured'" },
      element: {
        type: 'plain_text_input',
        action_id: 'persona_value',
        multiline: true,
        initial_value: currentPersona,
        placeholder: { type: 'plain_text', text: 'direct, action-oriented, conversational' }
      }
    }
  ]
};

return [{ json: { triggerId, modal: JSON.stringify(modal) } }];

const user = $('Lookup User (Action)').first().json;
const currentScope = (user && user.digest_scope) ? user.digest_scope : 'my_deals';
const triggerId = $('Parse Interactive Payload').first().json.triggerId;

const options = [
  { text: { type: 'plain_text', text: 'My deals \u2014 personal pipeline' }, value: 'my_deals' },
  { text: { type: 'plain_text', text: 'Team deals \u2014 my team\u2019s pipeline' }, value: 'team_deals' },
  { text: { type: 'plain_text', text: 'Full pipeline \u2014 org-wide top deals' }, value: 'top_pipeline' }
];

const initialOption = options.find(o => o.value === currentScope) || options[0];

const modal = {
  type: 'modal',
  callback_id: 'save_scope',
  title: { type: 'plain_text', text: 'Digest Scope' },
  submit: { type: 'plain_text', text: 'Save' },
  close: { type: 'plain_text', text: 'Cancel' },
  blocks: [
    {
      type: 'section',
      text: { type: 'mrkdwn', text: 'What pipeline view do you want in your morning digest?' }
    },
    {
      type: 'input',
      block_id: 'scope_block',
      label: { type: 'plain_text', text: 'Scope' },
      element: {
        type: 'radio_buttons',
        action_id: 'scope_value',
        initial_option: initialOption,
        options: options
      }
    }
  ]
};

return [{ json: { triggerId, modal: JSON.stringify(modal) } }];

const user = $('Lookup User (Action)').first().json;
const rawTime = (user && user.digest_time) ? user.digest_time : '06:00:00';
const currentTime = rawTime.substring(0, 5);  // strip seconds
const triggerId = $('Parse Interactive Payload').first().json.triggerId;

const modal = {
  type: 'modal',
  callback_id: 'save_digest_time',
  title: { type: 'plain_text', text: 'Digest Delivery Time' },
  submit: { type: 'plain_text', text: 'Save' },
  close: { type: 'plain_text', text: 'Cancel' },
  blocks: [
    {
      type: 'input',
      block_id: 'time_block',
      label: { type: 'plain_text', text: 'Delivery time (24-hour format)' },
      hint: { type: 'plain_text', text: 'Format: HH:MM \u2014 e.g. 06:00 for 6am, 07:30 for 7:30am' },
      element: {
        type: 'plain_text_input',
        action_id: 'time_value',
        initial_value: currentTime,
        placeholder: { type: 'plain_text', text: '06:00' }
      }
    }
  ]
};

